Literal.Value:
'{
  "description": "Ranking de Vendedores (Top 6) — dVendedor[NOME] + _Medidas[Total Receita]",
  "data": { "name": "dataset" },
  "width": "container",
  "height": "container",
  "background": "transparent",
  "title": {
    "text": "Ranking de Vendedores",
    "subtitle": "Top 6 · Receita",
    "anchor": "start",
    "color": "#ffffff",
    "fontSize": 15,
    "fontWeight": 600,
    "subtitleColor": "#8888A8",
    "subtitleFontSize": 11,
    "subtitlePadding": 4,
    "offset": 6,
    "dx": 2
  },
  "transform": [
    { "window": [{ "op": "rank", "as": "rnk" }], "sort": [{ "field": "Total Receita", "order": "descending" }] },
    { "filter": "datum.rnk <= 6" }
  ],
  "layer": [
    {
      "mark": { "type": "bar", "color": "rgba(139,92,246,0.12)", "cornerRadiusEnd": 6, "height": 10 },
      "encoding": {
        "y": { "field": "NOME", "type": "nominal", "sort": { "field": "Total Receita", "order": "descending" }, "title": null,
          "axis": { "labelColor": "#e5e7eb", "domainColor": "transparent", "tickColor": "transparent", "labelFontSize": 12, "labelLimit": 180 } },
        "x": { "aggregate": "max", "field": "Total Receita", "type": "quantitative", "title": null,
          "axis": { "labels": false, "grid": false, "domainColor": "transparent", "tickColor": "transparent" } }
      }
    },
    {
      "mark": { "type": "bar", "color": "#8B5CF6", "cornerRadiusEnd": 6, "height": 10 },
      "params": [
        { "name": "sel", "select": { "type": "point", "on": "click", "fields": ["NOME"], "clear": "dblclick" } }
      ],
      "encoding": {
        "y": { "field": "NOME", "type": "nominal", "sort": { "field": "Total Receita", "order": "descending" } },
        "x": { "field": "Total Receita", "type": "quantitative" },
        "tooltip": [
          { "field": "NOME", "type": "nominal", "title": "Vendedor" },
          { "field": "Total Receita", "type": "quantitative", "title": "Receita (R$)", "format": ",.2f" }
        ]
      }
    },
    {
      "mark": { "type": "text", "align": "left", "dx": 6, "color": "#9ca3af", "fontSize": 11 },
      "encoding": {
        "y": { "field": "NOME", "type": "nominal", "sort": { "field": "Total Receita", "order": "descending" } },
        "x": { "field": "Total Receita", "type": "quantitative" },
        "text": { "field": "Total Receita", "type": "quantitative", "format": ",.0f" }
      }
    }
  ],
  "config": { "view": { "stroke": "transparent" } }
}'
